// svg.shapes.js for SVG.js v3+ (Custom Implementation)
;(function() {
    if (typeof SVG === 'undefined') return;

    SVG.shapes = {
        defaults: {
            spikes: 7,
            inner: 50,
            outer: 100,
            edges: 7,
            radius: 100
        },
        star: function(settings) {
            settings = settings || {};
            var i, a, x, y, points = [],
                defaults = SVG.shapes.defaults,
                spikes = typeof settings.spikes === 'number' ? settings.spikes : defaults.spikes,
                inner = typeof settings.inner === 'number' ? settings.inner : defaults.inner,
                outer = typeof settings.outer === 'number' ? settings.outer : defaults.outer,
                degrees = 360 / spikes;

            for (i = 0; i < spikes; i++) {
                a = i * degrees - 90;
                x = outer + inner * Math.cos(a * Math.PI / 180);
                y = outer + inner * Math.sin(a * Math.PI / 180);
                points.push([x, y]);

                a += degrees / 2;
                x = outer + outer * Math.cos(a * Math.PI / 180);
                y = outer + outer * Math.sin(a * Math.PI / 180);
                points.push([x, y]);
            }
            return new SVG.List(points);
        },
        ngon: function(settings) {
            settings = settings || {};
            var i, a, x, y, points = [],
                defaults = SVG.shapes.defaults,
                edges = typeof settings.edges === 'number' ? settings.edges : defaults.edges,
                radius = typeof settings.radius === 'number' ? settings.radius : defaults.radius,
                degrees = 360 / edges;

            for (i = 0; i < edges; i++) {
                a = i * degrees - 90;
                x = radius + radius * Math.cos(a * Math.PI / 180);
                y = radius + radius * Math.sin(a * Math.PI / 180);
                points.push([x, y]);
            }
            return new SVG.List(points);
        }
    };

    // Helper to apply shape to existing element
    var applyShape = function(shapeFn, settings) {
        // Calculate points relative to 0,0
        var points = shapeFn(settings);
        
        // If we want to maintain the center or position, logic is needed.
        // For simple usage, we just replot.
        return this.plot(points);
    };

    // Extend Polyline, Polygon and Runner (for animation if supported)
    // Note: SVG.Runner might not support plot() straightforwardly for shapes without Animatable plugin support
    // But we define it for Polygon/Polyline
    SVG.extend(SVG.Polygon, SVG.Polyline, {
        star: function(settings) {
            return applyShape.call(this, SVG.shapes.star, settings);
        },
        ngon: function(settings) {
            return applyShape.call(this, SVG.shapes.ngon, settings);
        }
    });

    // Add to Container to create new shapes easily
    SVG.extend(SVG.Container, {
        star: function(settings) {
            return this.polygon().star(settings);
        },
        ngon: function(settings) {
            return this.polygon().ngon(settings);
        }
    });

})();
